using System;
using System.IO;
using Microsoft.Build.Logging.StructuredLogger;
using Microsoft.Build.Framework;

class Program
{
    static void Main(string[] args)
    {
        var binlogPath = args[0];
        var build = BinaryLog.ReadBuild(binlogPath);

        // Print all errors
        build.VisitAllChildren<Error>(error => {
            Console.WriteLine($"ERROR [{error.ProjectFile}]: {error.File}({error.LineNumber},{error.ColumnNumber}): error {error.Code}: {error.Text}");
        });

        Console.WriteLine("\n=== WARNINGS ===");
        build.VisitAllChildren<Warning>(warning => {
            if (warning.Code != null && (warning.Code.StartsWith("CS") || warning.Code.StartsWith("MSB")))
                Console.WriteLine($"WARNING [{warning.ProjectFile}]: {warning.File}({warning.LineNumber},{warning.ColumnNumber}): warning {warning.Code}: {warning.Text}");
        });
    }
}
EOF

