using System;
using System.IO;
using System.Linq;
using System.Collections.Generic;
using Microsoft.Build.Logging.StructuredLogger;
using Microsoft.Build.Framework;

class Program
{
    static void Main(string[] args)
    {
        var binlogPath = args[0];
        var build = BinaryLog.ReadBuild(binlogPath);

        Console.WriteLine("=== BUILD RESULT ===");
        Console.WriteLine($"Succeeded: {build.Succeeded}");
        Console.WriteLine();

        // Collect all errors
        var errors = new List<(string Project, string File, int Line, int Col, string Code, string Text)>();
        build.VisitAllChildren<Error>(error => {
            errors.Add((error.ProjectFile ?? "", error.File ?? "", error.LineNumber, error.ColumnNumber, error.Code ?? "", error.Text ?? ""));
        });

        Console.WriteLine($"=== ALL ERRORS ({errors.Count}) ===");
        foreach (var e in errors)
        {
            var proj = Path.GetFileName(e.Project);
            var file = Path.GetFileName(e.File);
            Console.WriteLine($"  [{proj}] {file}({e.Line},{e.Col}): error {e.Code}: {e.Text}");
        }
        Console.WriteLine();

        // Check project dependencies
        Console.WriteLine("=== PROJECT STRUCTURE ===");
        build.VisitAllChildren<Project>(project => {
            Console.WriteLine($"  Project: {Path.GetFileName(project.ProjectFile)} (Succeeded: {project.Succeeded})");
        });
        Console.WriteLine();

        // Check for project references
        Console.WriteLine("=== PROJECT REFERENCES (from items) ===");
        build.VisitAllChildren<AddItem>(item => {
            if (item.Name == "ProjectReference")
            {
                Console.WriteLine($"  {Path.GetFileName(item.Parent?.ToString() ?? "")} -> {item.FirstChild}");
            }
        });
        Console.WriteLine();

        // Find failed targets
        Console.WriteLine("=== FAILED TARGETS ===");
        build.VisitAllChildren<Target>(target => {
            if (!target.Succeeded)
            {
                var proj = target.Project;
                Console.WriteLine($"  [{Path.GetFileName(proj?.ProjectFile ?? "")}] Target '{target.Name}' FAILED");
            }
        });
    }
}
EOF

