            if (name != null && name.Contains("PackageReference"))
            {
                var project = GetProjectFile(node);
                Console.WriteLine($"  [{Path.GetFileName(project)}] Type={node.GetType().Name}: {name}");
            }
        });
        Console.WriteLine();

        // Get all nodes containing Newtonsoft
        Console.WriteLine("=== ALL NODES CONTAINING 'Newtonsoft' ===");
        build.VisitAllChildren<TreeNode>(node => {
            var name = node.ToString();
            if (name != null && name.Contains("Newtonsoft"))
            {
                var project = GetProjectFile(node);
                Console.WriteLine($"  [{Path.GetFileName(project)}] Type={node.GetType().Name}: {name}");
            }
        });
        Console.WriteLine();

        // Look for the project files themselves (embedded)
        Console.WriteLine("=== LOOKING FOR EMBEDDED PROJECT FILES ===");
        var archives = new List<string>();
        build.VisitAllChildren<TreeNode>(node => {
            if (node is SourceFile sf)
            {
                if (sf.Name != null && (sf.Name.Contains(".csproj") || sf.Name.Contains("UserService")))
                    Console.WriteLine($"  SourceFile: {sf.Name}");
            }
        });
        Console.WriteLine();

        // Print the build tree at top levels
        Console.WriteLine("=== TOP-LEVEL TREE ===");
        PrintTree(build, 0, 3);
    }

    static void PrintTree(BaseNode node, int depth, int maxDepth)
    {
        if (depth > maxDepth) return;
        var indent = new string(' ', depth * 2);
        var text = node.ToString();
        if (text != null && text.Length > 120) text = text.Substring(0, 120) + "...";
        Console.WriteLine($"{indent}{node.GetType().Name}: {text}");
        if (node is TreeNode tn)
        {
            foreach (var child in tn.Children.Take(10))
            {
                if (child is BaseNode bn)
                    PrintTree(bn, depth + 1, maxDepth);
            }
            if (tn.Children.Count > 10)
                Console.WriteLine($"{indent}  ... ({tn.Children.Count - 10} more children)");
        }
    }

    static string GetProjectFile(BaseNode node)
    {
        var current = node;
        while (current != null)
        {
            if (current is Project p) return p.ProjectFile ?? "";
            current = current.Parent as BaseNode;
        }
        return "";
    }
}
